mapper.select:
SELECT p.id AS post_id, p.caption, p.has_location, p.latitude, p.longitude, p.created_at, i.id AS image_id, i.sort_order, i.path AS image_path, i.content_type, i.size_bytes, i.width, i.height FROM posts p LEFT JOIN post_images i ON p.id = i.post_id
AND p.id < #{lastId.value}
ORDER BY p.created_at DESC, p.id DESC LIMIT #{size}

SELECT p.id AS post_id, p.caption, p.has_location, p.latitude, p.longitude, p.created_at, i.id AS image_id, i.sort_order, i.path AS image_path, i.content_type, i.size_bytes, i.width, i.height FROM posts p LEFT JOIN post_images i ON p.id = i.post_id
AND p.user_id = #{userId.value}
AND p.id < #{lastId.value}
ORDER BY p.created_at DESC, p.id DESC LIMIT #{size}

SELECT p.id AS post_id, p.caption, p.has_location, p.latitude, p.longitude, p.created_at, i.id AS image_id, i.sort_order, i.path AS image_path, i.content_type, i.size_bytes, i.width, i.height FROM posts p LEFT JOIN post_images i ON p.id = i.post_id WHERE p.caption LIKE CONCAT('%', #{keyword}, '%')
AND p.id < #{lastId}
ORDER BY p.created_at DESC, p.id DESC LIMIT #{size}
